from docx import Document
from docx.enum.section import WD_SECTION
from docx.enum.style import WD_STYLE_TYPE
from docx.enum.text import WD_ALIGN_PARAGRAPH
from docx.oxml import OxmlElement
from docx.oxml.ns import qn
from docx.shared import Cm, Pt


OUTPUT_PATH = "DIVA_Переддипломна_практика.docx"


def set_default_style(doc: Document) -> None:
    section = doc.sections[0]
    section.top_margin = Cm(2)
    section.bottom_margin = Cm(2)
    section.left_margin = Cm(3)
    section.right_margin = Cm(1)

    normal = doc.styles["Normal"]
    normal.font.name = "Times New Roman"
    normal._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    normal.font.size = Pt(14)
    pf = normal.paragraph_format
    pf.line_spacing = 1.5
    pf.first_line_indent = Cm(1.25)
    pf.space_after = Pt(0)
    pf.space_before = Pt(0)
    pf.alignment = WD_ALIGN_PARAGRAPH.JUSTIFY

    if "Custom Heading 1" not in doc.styles:
        h1 = doc.styles.add_style("Custom Heading 1", WD_STYLE_TYPE.PARAGRAPH)
    else:
        h1 = doc.styles["Custom Heading 1"]
    h1.base_style = normal
    h1.font.name = "Times New Roman"
    h1._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    h1.font.size = Pt(14)
    h1.font.bold = True
    h1.paragraph_format.alignment = WD_ALIGN_PARAGRAPH.CENTER
    h1.paragraph_format.first_line_indent = None
    h1.paragraph_format.line_spacing = 1.5
    h1.paragraph_format.space_before = Pt(12)
    h1.paragraph_format.space_after = Pt(12)

    if "Custom Heading 2" not in doc.styles:
        h2 = doc.styles.add_style("Custom Heading 2", WD_STYLE_TYPE.PARAGRAPH)
    else:
        h2 = doc.styles["Custom Heading 2"]
    h2.base_style = normal
    h2.font.name = "Times New Roman"
    h2._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    h2.font.size = Pt(14)
    h2.font.bold = True
    h2.paragraph_format.alignment = WD_ALIGN_PARAGRAPH.LEFT
    h2.paragraph_format.first_line_indent = None
    h2.paragraph_format.line_spacing = 1.5
    h2.paragraph_format.space_before = Pt(12)
    h2.paragraph_format.space_after = Pt(6)


def add_paragraph(doc: Document, text: str, *, align=None, bold=False, first_line=True, italic=False) -> None:
    p = doc.add_paragraph(style="Normal")
    if not first_line:
        p.paragraph_format.first_line_indent = None
    if align is not None:
        p.alignment = align
    run = p.add_run(text)
    run.bold = bold
    run.italic = italic
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(14)


def add_heading_1(doc: Document, text: str) -> None:
    doc.add_paragraph(text, style="Custom Heading 1")


def add_heading_2(doc: Document, text: str) -> None:
    doc.add_paragraph(text, style="Custom Heading 2")


def add_toc(doc: Document) -> None:
    p = doc.add_paragraph()
    p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = p.add_run("ЗМІСТ")
    run.bold = True
    run.font.name = "Times New Roman"
    run._element.rPr.rFonts.set(qn("w:eastAsia"), "Times New Roman")
    run.font.size = Pt(14)

    p = doc.add_paragraph()
    p.paragraph_format.first_line_indent = None
    fld = OxmlElement("w:fldSimple")
    fld.set(qn("w:instr"), 'TOC \\o "1-3" \\h \\z \\u')
    r = OxmlElement("w:r")
    t = OxmlElement("w:t")
    t.text = "Оновіть поле змісту в Word для відображення сторінок."
    r.append(t)
    fld.append(r)
    p._p.append(fld)


def add_page_break(doc: Document) -> None:
    doc.add_page_break()


