def add_figure(doc: Document, number: str, caption: str) -> None:
    add_paragraph(doc, "[Місце для рисунка]", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False, italic=True)
    add_paragraph(doc, f"Рисунок {number} – {caption}", align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False)


def write_body(doc: Document, paragraphs: list[str]) -> None:
    for text in paragraphs:
        if text.startswith("[ДОДАТОК"):
            add_paragraph(doc, text, align=WD_ALIGN_PARAGRAPH.CENTER, first_line=False, italic=True)
        else:
            add_paragraph(doc, text)


